mapper.select:
SELECT

FROM project_business_info t0


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.type = #{request.type}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.tenant_id = #{request.tenantId}


    AND t0.project_id = #{request.projectId}


    AND t0.related_bus_no = #{request.relatedBusNo}


    AND t0.business_type = #{request.businessType}


    AND t0.product_name = #{request.productName}


    AND t0.rist_type_after_guarantee = #{request.ristTypeAfterGuarantee}


    AND t0.divided_insurance_debtor = #{request.dividedInsuranceDebtor}


    AND t0.divided_insurance_security = #{request.dividedInsuranceSecurity}


    AND t0.divided_insurance_again_security = #{request.dividedInsuranceAgainSecurity}


    AND t0.divided_insurance_other = #{request.dividedInsuranceOther}


    AND t0.risk_compensation = #{request.riskCompensation}


    AND t0.aid = #{request.aid}


    AND t0.aname = #{request.aname}


    AND t0.acode = #{request.acode}


    AND t0.bid = #{request.bid}


    AND t0.bcode = #{request.bcode}


    AND t0.bname = #{request.bname}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
